using System.ComponentModel;
using Microsoft.Extensions.AI;
using ModelContextProtocol.Server;

/// <summary>
/// Reusable prompt templates exposed to MCP clients.
/// </summary>
[McpServerPromptType]
internal static class SummarizePrompts
{
    [McpServerPrompt, Description("Summarize the provided content into a concise paragraph.")]
    public static ChatMessage Summarize(
        [Description("The text content to summarize")] string content) =>
        new(ChatRole.User, $"Summarize the following content into a concise paragraph:\n\n{content}");

    [McpServerPrompt, Description("Summarize content with a specific style (e.g. bullets, executive, technical).")]
    public static ChatMessage SummarizeWithStyle(
        [Description("The text content to summarize")] string content,
        [Description("The summarization style: bullets, executive, or technical")] string style = "bullets") =>
        new(ChatRole.User, $"Summarize the following content in '{style}' style:\n\n{content}");
}

