using System.ComponentModel;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

/// <summary>
/// MCP tools that call an external API via HttpClient.
/// HttpClient and ILogger are injected through the constructor and are
/// not exposed in the tool schema.
/// </summary>
[McpServerToolType]
internal class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    [McpServerTool(Name = "fetch_resource")]
    [Description("Fetches a resource from the external API by its identifier.")]
    public async Task<string> FetchResource(
        [Description("The unique identifier of the resource to retrieve")] string id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching resource {Id}", id);

        var response = await httpClient.GetAsync($"/api/resources/{id}", cancellationToken);
        response.EnsureSuccessStatusCode();

        return await response.Content.ReadAsStringAsync(cancellationToken);
    }

    [McpServerTool(Name = "search_resources")]
    [Description("Searches the external API for resources matching a query string.")]
    public async Task<string> SearchResources(
        [Description("The search query")] string query,
        [Description("Maximum number of results to return")] int maxResults = 10,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Searching resources with query {Query}", query);

        var response = await httpClient.GetAsync(
            $"/api/resources?q={Uri.EscapeDataString(query)}&limit={maxResults}",
            cancellationToken);
        response.EnsureSuccessStatusCode();

        return await response.Content.ReadAsStringAsync(cancellationToken);
    }
}

